words = sentence.split()
    primes = []
    for word in words:
        l = len(word)
        if l < 2:
            continue
        is_prime = True
        if l == 2:
            is_prime = True
        elif l % 2 == 0:
            is_prime = False
        else:
            for i in range(3, int(l**0.5) + 1, 2):
                if l % i == 0:
                    is_prime = False
                    break
        if is_prime:
            primes.append(word)
    return ' '.join(primes)
